package internal

import (
	"fmt"
	"strconv"
	"time"

	"github.com/redis/go-redis/v9/internal/util"
)

func AppendArg(b []byte, v interface{}) []byte {
	switch v := v.(type) {
	case nil:
		return append(b, "<nil>"...)
	case string:
		return appendUTF8String(b, util.StringToBytes(v))
	case []byte:
		return appendUTF8String(b, v)
	case int:
		return strconv.AppendInt(b, int64(v), 10)
	case int8:
		return strconv.AppendInt(b, int64(v), 10)
	case int16:
		return strconv.AppendInt(b, int64(v), 10)
	case int32:
		return strconv.AppendInt(b, int64(v), 10)
	case int64:
		return strconv.AppendInt(b, v, 10)
	case uint:
		return strconv.AppendUint(b, uint64(v), 10)
	case uint8:
		return strconv.AppendUint(b, uint64(v), 10)
	case uint16:
		return strconv.AppendUint(b, uint64(v), 10)
	case uint32:
		return strconv.AppendUint(b, uint64(v), 10)
	case uint64:
		return strconv.AppendUint(b, v, 10)
	case float32:
		return strconv.AppendFloat(b, float64(v), 'f', -1, 64)
	case float64:
		return strconv.AppendFloat(b, v, 'f', -1, 64)
	case bool:
		if v {
			return append(b, "true"...)
		}
		return append(b, "false"...)
	case time.Time:
		return v.AppendFormat(b, time.RFC3339Nano)
	default:
		return append(b, fmt.Sprint(v)...)
	}
}

func appendUTF8String(dst []byte, src []byte) []byte {
	dst = append(dst, src...)
	return dst
}

//go:build gofuzz
// +build gofuzz

package fuzz

import (
	"context"
	"time"

	"github.com/redis/go-redis/v9"
)

const (
	minDataLength     = 4
	redisAddr         = ":6379"
	dialTimeout       = 10 * time.Second
	readTimeout       = 10 * time.Second
	writeTimeout      = 10 * time.Second
	poolSize          = 10
	poolTimeout       = 10 * time.Second
	scanCount         = 10
	maxIterPercentage = 256 // Use first byte as percentage of data length
)

var (
	ctx = context.Background()
	rdb *redis.Client
)

type redisOperation func(key, value string)

func init() {
	rdb = redis.NewClient(&redis.Options{
		Addr:         redisAddr,
		DialTimeout:  dialTimeout,
		ReadTimeout:  readTimeout,
		WriteTimeout: writeTimeout,
		PoolSize:     poolSize,
		PoolTimeout:  poolTimeout,
	})
}

func Fuzz(data []byte) int {
	if len(data) < minDataLength {
		return -1
	}

	maxIter := (int(data[0]) * len(data)) / maxIterPercentage
	if maxIter == 0 {
		maxIter = 1 // Ensure at least one iteration
	}

	operations := []redisOperation{
		func(key, value string) { rdb.Set(ctx, key, value, 0).Err() },
		func(key, value string) { rdb.Get(ctx, key).Result() },
		func(key, value string) { rdb.Incr(ctx, key).Result() },
		func(key, value string) {
			var cursor uint64
			rdb.Scan(ctx, cursor, key, scanCount).Result()
		},
	}

	dataStr := string(data)

	for i := 0; i < maxIter && i < len(data); i++ {
		start := i % len(data)
		end := (i + 1) % len(data)
		if end <= start {
			end = len(data)
		}

		key := dataStr[start:end]
		opIndex := i % len(operations)

		operations[opIndex](key, dataStr)
	}

	return 1
}
